import{_ as t,o as d,c as o,a4 as r}from"./chunks/framework.CiaPn2nJ.js";const u=JSON.parse('{"title":"API Design & Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture/api-design.md","filePath":"reference/architecture/api-design.md"}'),a={name:"reference/architecture/api-design.md"};function c(n,e,s,i,l,h){return d(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="api-design-reference" tabindex="-1">API Design &amp; Reference <a class="header-anchor" href="#api-design-reference" aria-label="Permalink to &quot;API Design &amp; Reference&quot;">​</a></h1><blockquote><p><strong>Last Updated</strong>: 2026-06-28</p></blockquote><h2 id="api-style" tabindex="-1">API Style <a class="header-anchor" href="#api-style" aria-label="Permalink to &quot;API Style&quot;">​</a></h2><p><code>@jsvision/core</code> is an <strong>ESM-only TypeScript library</strong>. The public contract is the set of exports of <code>src/engine/index.ts</code> — the single entry point. Everything else under <code>src/engine/**</code> is internal and may change without a major bump (see the README &quot;Versioning &amp; stability&quot; policy and <a href="/jsvision/pr-preview/pr-90/reference/decisions/ADR-001-esm-zero-dependency.html">ADR-001</a>).</p><ul><li><strong>Module system</strong>: ESM only; <code>require()</code> is unsupported (no CommonJS condition).</li><li><strong>Import specifiers</strong>: NodeNext — <code>.js</code> extensions on source imports.</li><li><strong>Stability</strong>: pre-1.0 the surface may change between minors; the index exports are the contract, internals are not.</li></ul><h2 id="conventions" tabindex="-1">Conventions <a class="header-anchor" href="#conventions" aria-label="Permalink to &quot;Conventions&quot;">​</a></h2><ul><li><strong>Pure where possible</strong>: rendering, decoding, and colour encoding are pure functions. The only stateful API is the host.</li><li><strong>Injectable seams</strong>: capabilities (<code>TerminalQuery</code>), the runtime (<code>RuntimeAdapter</code>), and the style encoder (<code>StyleEncoder</code>) are all injectable — tests pass fakes, production passes real implementations.</li><li><strong>Frozen results</strong>: a resolved <code>CapabilityProfile</code> is deeply frozen.</li><li><strong>Typed errors</strong>: failures throw subclasses of <code>TuiError</code>.</li></ul><h2 id="public-surface-by-subsystem" tabindex="-1">Public Surface by Subsystem <a class="header-anchor" href="#public-surface-by-subsystem" aria-label="Permalink to &quot;Public Surface by Subsystem&quot;">​</a></h2><p>The reference below groups the <code>src/engine/index.ts</code> exports. Each symbol carries JSDoc in source (purpose, params, returns, side effects).</p><h3 id="package" tabindex="-1">Package <a class="header-anchor" href="#package" aria-label="Permalink to &quot;Package&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>VERSION</code></td><td>const</td><td>The package version string (SemVer).</td></tr></tbody></table><h3 id="capability-detection-rd-02" tabindex="-1">Capability detection (RD-02) <a class="header-anchor" href="#capability-detection-rd-02" aria-label="Permalink to &quot;Capability detection (RD-02)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>resolveCapabilities(options)</code></td><td>fn</td><td>Resolve a frozen <code>CapabilityProfile</code> from env/platform/table/override (sync).</td></tr><tr><td><code>resolveCapabilitiesAsync(options)</code></td><td>fn</td><td>As above plus a bounded layer-2 live <code>TerminalQuery</code>.</td></tr><tr><td><code>CapabilityProfile</code>, <code>CapabilityResolution</code>, <code>CapabilityReasons</code></td><td>type</td><td>The resolved profile, result, and per-field provenance.</td></tr><tr><td><code>ColorDepth</code>, <code>GlyphCaps</code>, <code>KeyboardCaps</code>, <code>MouseCaps</code>, <code>OscCaps</code>, <code>UnicodeCaps</code></td><td>type</td><td>Capability field shapes.</td></tr><tr><td><code>ResolveOptions</code>, <code>SyncResolveOptions</code>, <code>TerminalQuery</code></td><td>type</td><td>Inputs + the live-query seam.</td></tr><tr><td><code>Platform</code>, <code>ReasonLayer</code>, <code>DeepPartial</code></td><td>type</td><td>Supporting types.</td></tr></tbody></table><h3 id="input-decoder-rd-06" tabindex="-1">Input decoder (RD-06) <a class="header-anchor" href="#input-decoder-rd-06" aria-label="Permalink to &quot;Input decoder (RD-06)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>createDecoderState()</code></td><td>fn</td><td>Create the mutable decoder carry state.</td></tr><tr><td><code>decode(bytes, state, options)</code></td><td>fn</td><td>Decode a byte chunk into <code>InputEvent</code>s (pure transform + carry).</td></tr><tr><td><code>flush(state)</code></td><td>fn</td><td>Flush a pending escape/partial sequence at end-of-input.</td></tr><tr><td><code>createKeymap()</code></td><td>fn</td><td>Build the default key map.</td></tr><tr><td><code>ESC_TIMEOUT_MS</code>, <code>PASTE_CAP_BYTES</code></td><td>const</td><td>Decoder timing/size bounds.</td></tr><tr><td><code>KeyEvent</code>, <code>MouseEvent</code>, <code>WheelEvent</code>, <code>PasteEvent</code>, <code>FocusEvent</code>, <code>InputEvent</code>, <code>QueryResponse</code></td><td>type</td><td>Decoded event shapes.</td></tr><tr><td><code>DecodeResult</code>, <code>DecoderState</code>, <code>DecodeOptions</code>, <code>Keymap</code></td><td>type</td><td>Decoder I/O types.</td></tr></tbody></table><h3 id="rendering-engine-rd-04" tabindex="-1">Rendering engine (RD-04) <a class="header-anchor" href="#rendering-engine-rd-04" aria-label="Permalink to &quot;Rendering engine (RD-04)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>ScreenBuffer</code></td><td>class</td><td>Width-correct cell grid; <code>set</code>/<code>text</code>/<code>fillRect</code>/<code>box</code>/<code>shadow</code>/<code>rows</code>.</td></tr><tr><td><code>serialize(current, previous, options)</code></td><td>fn</td><td>Pure damage-diff → minimal ANSI (bytes ∝ damage).</td></tr><tr><td><code>defaultEncodeStyle</code></td><td>const</td><td>The default <code>StyleEncoder</code> (RD-05 <code>encodeStyle</code>).</td></tr><tr><td><code>fallbackGlyph(char, caps)</code></td><td>fn</td><td>Capability-driven ASCII glyph fallback.</td></tr><tr><td><code>Attr</code></td><td>const</td><td>Attribute bit flags (<code>bold</code>, <code>reverse</code>, …).</td></tr><tr><td><code>charWidth(cp, mode)</code></td><td>fn</td><td>Display width of a code point.</td></tr><tr><td><code>hyperlink</code>, <code>setClipboard</code>, <code>setTitle</code>, <code>bell</code>, <code>notify</code></td><td>fn</td><td>OSC feature emitters.</td></tr><tr><td><code>cursor</code>, <code>CSI</code>, <code>SGR_RESET</code>, <code>SYNC_BEGIN</code>, <code>SYNC_END</code>, <code>cursorTo</code></td><td>const/fn</td><td>Cursor + low-level ANSI helpers.</td></tr><tr><td><code>Cell</code>, <code>Style</code>, <code>Color</code>, <code>Ansi16Name</code>, <code>AttrMask</code>, <code>WidthMode</code>, <code>StyleEncoder</code>, <code>RenderOptions</code></td><td>type</td><td>Render data + option types.</td></tr></tbody></table><h3 id="color-styling-rd-05" tabindex="-1">Color &amp; styling (RD-05) <a class="header-anchor" href="#color-styling-rd-05" aria-label="Permalink to &quot;Color &amp; styling (RD-05)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>encode(color, role, depth)</code></td><td>fn</td><td>Encode one colour to a standalone SGR for a depth.</td></tr><tr><td><code>encodeStyle(fg, bg, attrs, caps)</code></td><td>fn</td><td>Merge attrs + fg + bg into one depth-aware SGR (the serialize default).</td></tr><tr><td><code>styleKey(fg, bg, attrs)</code></td><td>fn</td><td>Stable key for a style (cache/dedup).</td></tr><tr><td><code>nearest256(rgb)</code>, <code>nearest16(rgb)</code></td><td>fn</td><td>Redmean nearest-colour downsampling.</td></tr><tr><td><code>InvalidColorError</code></td><td>class</td><td>Thrown on malformed colour input (extends <code>TuiError</code>).</td></tr><tr><td><code>PALETTE</code>, <code>defaultTheme</code></td><td>const</td><td>DOS-16 palette + typed default theme.</td></tr><tr><td><code>ColorRole</code>, <code>Rgb</code>, <code>Theme</code>, <code>ThemeRole</code></td><td>type</td><td>Colour/theme types.</td></tr></tbody></table><h3 id="host-lifecycle-rd-07-—-the-only-stateful-subsystem" tabindex="-1">Host &amp; lifecycle (RD-07) — the only stateful subsystem <a class="header-anchor" href="#host-lifecycle-rd-07-—-the-only-stateful-subsystem" aria-label="Permalink to &quot;Host &amp; lifecycle (RD-07) — the only stateful subsystem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>createHost(options)</code></td><td>fn</td><td>Native tty host: raw mode, alt-screen, signals, guaranteed restore.</td></tr><tr><td><code>detectTty(streams)</code></td><td>fn</td><td>Pre-start TTY probe (RD-08 PF-001).</td></tr><tr><td><code>createTerminalQuery(options)</code></td><td>fn</td><td>Real tty-backed <code>TerminalQuery</code> (completes RD-02 layer-2).</td></tr><tr><td><code>Host</code>, <code>HostOptions</code>, <code>ResizeEvent</code>, <code>RuntimeAdapter</code>, <code>HostSignal</code>, <code>TimerHandle</code>, <code>StreamOptions</code>, <code>TerminalQueryOptions</code>, <code>ManagedTerminalQuery</code></td><td>type</td><td>Host API + the injectable runtime seam.</td></tr></tbody></table><h3 id="safety-rd-08" tabindex="-1">Safety (RD-08) <a class="header-anchor" href="#safety-rd-08" aria-label="Permalink to &quot;Safety (RD-08)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Kind</th><th>Summary</th></tr></thead><tbody><tr><td><code>sanitize(str)</code></td><td>fn</td><td>Canonical injection boundary: strip control bytes from untrusted text.</td></tr><tr><td><code>evaluateEssentials(facts)</code>, <code>essentialsMet(report)</code>, <code>assertEssentials(facts)</code></td><td>fn</td><td>The pre-start essentials gate.</td></tr><tr><td><code>createLogger(options)</code></td><td>fn</td><td>Screen-safe logger (never corrupts the alt-screen).</td></tr><tr><td><code>redactEvent(event)</code>, <code>dumpCaps(caps)</code></td><td>fn</td><td>Redaction + capability dump (no secrets/PII).</td></tr><tr><td><code>TuiError</code>, <code>EssentialsNotMetError</code>, <code>LoggerConfigError</code></td><td>class</td><td>Typed error model.</td></tr><tr><td><code>EssentialsReport</code>, <code>Degradation</code>, <code>HostFacts</code>, <code>Logger</code>, <code>LoggerOptions</code>, <code>LogLevel</code>, <code>LogRecord</code>, <code>LogSink</code>, <code>LoggerFs</code>, <code>RedactedEvent</code></td><td>type</td><td>Safety types.</td></tr></tbody></table><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>All thrown errors extend <code>TuiError</code>. Notable cases:</p><table tabindex="0"><thead><tr><th>Error</th><th>When</th><th>Notes</th></tr></thead><tbody><tr><td><code>EssentialsNotMetError</code></td><td>The essentials gate fails (e.g. non-TTY / <code>TERM=dumb</code>)</td><td>Degrades, never crashes mid-render</td></tr><tr><td><code>InvalidColorError</code></td><td>A malformed colour reaches <code>encode()</code></td><td>The render-path encoder seam degrades crash-safe instead</td></tr><tr><td><code>LoggerConfigError</code></td><td>Invalid logger configuration</td><td>Thrown at logger construction</td></tr></tbody></table><h2 id="performance-contract" tabindex="-1">Performance Contract <a class="header-anchor" href="#performance-contract" aria-label="Permalink to &quot;Performance Contract&quot;">​</a></h2><ul><li>Composing + diff-serializing a 200×50 frame has a median ≤ 16 ms on a modern dev machine (<code>npm run bench</code>; enforced off-CI by <code>test/perf-budget.spec.test.ts</code>).</li><li>A steady-state single-cell update emits a byte count <strong>independent of screen size</strong> (output ∝ damage).</li><li>Capability detection against a non-responding terminal falls back within <code>timeoutMs</code> + slack.</li></ul>',28)])])}const y=t(a,[["render",c]]);export{u as __pageData,y as default};
